#include <stdio.h>
int main() {
    int T, N;
    scanf("%d", &T);
    while (T--) {
        scanf("%d", &N);
        int bits = 1, nibbles = 0, bytes = 0;
        for (int i = 0; i < N; i++) {
            if (i % 2 == 1) {
                nibbles++;
                bits--;
            }
            if (i % 8 == 7) {
                bytes++;
                nibbles--;
            }
            if (i % 16 == 15) {
                bits += 2;
                bytes--;
            }
        }
        printf("%d %d %d\n", bits, nibbles, bytes);
    }
    return 0;
}

